import clsx from 'clsx';
import type { FC } from 'react';
import React, { useContext } from 'react';
import { Tag } from '../tag';
import type { MultipleSelectTagProps, MultipleSelectMaxTagProps, SelectValue } from './internal.interface';
import { SelectContext } from './context/SelectContext';
import { Popover } from '../popover';
import { Space } from '../space';

/**
 * 默认的 tag renderer
 */
function MultipleSelectTag<V extends SelectValue>({
  value,
  title,
  closable,
  disabled,
  onClose,
  children,
}: MultipleSelectTagProps<V>) {
  const { selectorCssScope: cssScope, size } = useContext(SelectContext);
  const className = clsx(cssScope('__tag'));
  return (
    <Tag
      key={value as React.Key}
      title={title}
      className={className}
      color="neutral-option"
      size={size}
      closable={closable}
      visible
      onClose={onClose}
      disabled={disabled}
    >
      {children}
    </Tag>
  );
}
export const defaultTagRenderer = <V extends SelectValue>(props: MultipleSelectTagProps<V>) => (
  <MultipleSelectTag {...props} />
);

/**
 * 默认的 max tag renderer
 */
const MultipleSelectMaxTag: FC<
  MultipleSelectMaxTagProps & {
    tags: MultipleSelectTagProps<SelectValue>[];
  }
> = ({ disabled, tags }) => {
  const { selectorCssScope: cssScope, size, tagRenderer } = useContext(SelectContext);
  const className = clsx(cssScope('__tag'));

  const tagNode = (
    <Tag
      className={className}
      style={{ justifyContent: 'center' }}
      color="neutral-option"
      size={size}
      disabled={disabled}
    >
      {`+${tags.length}`}
    </Tag>
  );

  return (
    <Popover
      mode="pure"
      overlayClassName={cssScope('__overlay')}
      content={
        <div className={cssScope('__overlay-scrollArea')}>
          <Space
            size={4}
            wrap
            inline={false}
            shouldItemConfinedToContainer
            itemKey={index => tags[index].value as React.Key}
          >
            {tags.map(tag => (
              <React.Fragment key={tag.value as React.Key}>{tagRenderer(tag)}</React.Fragment>
            ))}
          </Space>
        </div>
      }
      visible={tags.length === 0 ? false : undefined} // 不指定这个在 tags 从有到无的时候会显示一个空的 popover
      disabled={tags.length === 0}
    >
      {tagNode}
    </Popover>
  );
};

export const defaultMaxTagRenderer = <V extends SelectValue>(
  props: MultipleSelectMaxTagProps,
  tags: MultipleSelectTagProps<V>[],
) => <MultipleSelectMaxTag {...props} tags={tags} />;
